// Получаем оригинальные статьи до сохранения
const splitOutItems = $items("14. Разбивка массива articles на отдельные статьи");
const articles = splitOutItems.map(item => ({
  source_url: item.json.articles?.source_url || item.json.source_url,
  title: item.json.articles?.scraped_title || item.json.scraped_title,
  full_text: item.json.articles?.full_text || item.json.full_text,
  processed_at: item.json.articles?.processed_at || item.json.processed_at,
  quality_flags: item.json.articles?.quality_flags || item.json.quality_flags
}));

return {
  json: {
    articles: articles,
    ready_for_ai: true,
    total_articles: articles.length,
    timestamp: new Date().toISOString()
  }
};

// 1. Получаем все входящие элементы из предыдущей ноды (на скрине слева)
const inputItems = $input.all();

// 2. Считаем длину полученного массива (количество статей)
const processedCount = inputItems.length;

// 3. Возвращаем результат и формируем нужное сообщение
return [{
  json: {
    message: `🗂 Уже обработано ссылок: ${processedCount}`,
    processedCount: processedCount
  }
}];

const count = $input.all().length;

return [{
  json: {
    message: `📰 Было прочитано ${count} ссылок`,
    count: count
  }
}];

const count = $input.all().length;

return [{
  json: {
    message: `📰 Получено ссылок за последние сутки ${count}`,
    count: count
  }
}];

const count = $input.all().length;

return [{
  json: {
    message: `📰 Осталось ссылок после фильтрации - ${count}`,
    count: count
  }
}];

// Собрать массив обработанных URL из входного потока
function normalizeUrl(u) {
  try {
    const url = new URL(u.trim());
    // убираем UTM и прочие маркеры
    ['utm_source','utm_medium','utm_campaign','utm_term','utm_content','gclid','fbclid','ref','ref_src'].forEach(p => url.searchParams.delete(p));
    // trailing slash нормализуем
    if (url.pathname !== '/' && url.pathname.endsWith('/')) url.pathname = url.pathname.slice(0, -1);
    // приводим хост к нижнему регистру
    url.hostname = url.hostname.toLowerCase();
    return url.toString();
  } catch {
    return (u || '').trim();
  }
}

const processed = $input.all()
  .map(i => i.json?.URL)
  .filter(Boolean)
  .map(normalizeUrl);

// Пишем в workflow static data
const s = $getWorkflowStaticData('global');
s.processedUrls = processed;        // массив на текущий ран
s.seenNow = [];                     // для дедупа в рамках текущего запуска

// Пробрасываем вход дальше без изменений (или вернём пустой item — как удобнее)
return $input.all();

// ---- URL нормализация (устойчивая к мусору) ----
function norm(u) {
  try {
    const s = String(u || '').trim();
    if (!s) return '';
    const url = new URL(s);
    url.hostname = url.hostname.toLowerCase().replace(/^www\./, '');
    // вычищаем маркеры и мусор
    ['utm_source','utm_medium','utm_campaign','utm_term','utm_content','gclid','fbclid','ref','ref_src','m']
      .forEach(p => url.searchParams.delete(p));
    // убираем хвостовой слеш (кроме корня)
    if (url.pathname !== '/' && url.pathname.endsWith('/')) url.pathname = url.pathname.slice(0, -1);
    url.hash = '';
    return url.toString();
  } catch {
    return String(u || '').trim();
  }
}

// ---- 1) Собираем Set обработанных URL из Airtable ----
const all = $input.all();
const processedSet = new Set();

for (const it of all) {
  const p = it?.json?.URL;            // у записей Airtable есть поле URL
  if (p) {
    const n = norm(p);
    if (n) processedSet.add(n);
  }
}

// ---- 2) Фильтруем только статьи ----
const seen = new Set();                // дедуп внутри текущего запуска
const out = [];

for (const it of all) {
  const j = it.json || {};

  // пропускаем записи из Airtable (они уже учтены выше)
  if (j.URL) continue;

  // достаём ссылку статьи из разных возможных полей
  const raw =
    j.link ||
    j.url ||
    (typeof j.id === 'string' && j.id.startsWith('http') ? j.id : null) ||
    j.guid ||
    j?.enclosure?.url;

  if (!raw) continue;

  const n = norm(raw);
  if (!n) continue;

  // если уже обработанo или повтор внутри этого батча — пропускаем
  if (processedSet.has(n) || seen.has(n)) continue;

  seen.add(n);
  out.push(it); // возвращаем оригинальный item статьи
}

return out;

// 1. Получаем объект от ScrapingBee
const scrapedResult = $input.item.json;

// Helper function: Safely parse potentially malformed JSON
function safeJsonParse(jsonString) {
  if (!jsonString) return null;

  try {
    return JSON.parse(jsonString);
  } catch (e1) {
    try {
      const cleaned = jsonString
        .replace(/\\'/g, "'")
        .replace(/\n/g, '\\n')
        .replace(/\r/g, '\\r')
        .replace(/\t/g, '\\t');
      return JSON.parse(cleaned);
    } catch (e2) {
      try {
        const match = jsonString.match(/\{[^]*\}/);
        if (match) return JSON.parse(match[0]);
      } catch (e3) {
        console.error('All JSON parse attempts failed:', e3.message);
        return null;
      }
    }
  }
  return null;
}

// Helper function: Clean junk from article text
function cleanArticleText(text) {
  if (!text) return '';

  let cleaned = text;

  // Define cleanup patterns
  const junkPatterns = [
    // Cookie consent (matches "We process your data...")
    /We (use|process) (cookies?|your data)[^]*?privacy policy[^]*?\n/gi,
    /This (website|site) uses (cookies?|tracking)[^]{0,300}?\n/gi,
    /Accept (all )?cookies?[^]*?\n/gi,
    /Cookie (settings?|preferences?)[^]*?\n/gi,
    /On\nThese cookies[^]*?---/gi,  // Ars Technica cookie sections

    // Navigation
    /Search dialog\.{3}\n*/gi,
    /Sign in dialog\.{3}\n*/gi,
    /Loading\.{3}\n*/gi,
    /Skip to (content|main)\n/gi,
    /Text\nsettings[^]*?Minimize to nav\n/gi,  // Text settings widget

    // Footer junk
    /Customize\s*$/gi,
    /Prev story\n/gi,
    /Next story\n/gi,

    // Comment sections
    /\d+ Comments\nComments\nForum view\nLoading comments\.{3}/gi,

    // Ad/tracking pixels at end
    /!\[\]\(https:\/\/(dc\.ads\.linkedin|t\.co|analytics\.twitter)[^)]+\)/gi
  ];

  // Apply cleanup
  for (const pattern of junkPatterns) {
    cleaned = cleaned.replace(pattern, '');
  }

  // Clean excessive whitespace
  cleaned = cleaned.replace(/\n{3,}/g, '\n\n').trim();

  return cleaned;
}

// 2. Проверяем ai_response
if (!scrapedResult || !scrapedResult.ai_response) {
  return {
    json: {
      error: true,
      error_message: 'Missing ai_response from ScrapingBee',
      error_type: 'missing_response',
      source_url: scrapedResult?.['resolved-url'] || scrapedResult?.url || 'unknown',
      raw_response_preview: JSON.stringify(scrapedResult).substring(0, 200)
    }
  };
}

// 3. Парсим ai_response
const scrapedData = safeJsonParse(scrapedResult.ai_response);

if (!scrapedData) {
  return {
    json: {
      error: true,
      error_message: 'Failed to parse ai_response JSON',
      error_type: 'json_parse_error',
      source_url: scrapedResult?.['resolved-url'] || scrapedResult?.url || 'unknown',
      raw_response: scrapedResult.ai_response?.substring(0, 500) || 'no response'
    }
  };
}

// 4. Получаем RSS данные
const inputItemIndex = $input.item.pairedItem?.item ?? 0;
const inputItems = $items("9. Фильтруем на уникальность");
const originalItem = inputItems[inputItemIndex]?.json || {};

// 5. Extract и clean данные
const scrapedTitle = (scrapedData.title || scrapedData.main_title || '').trim();
const rawText = (scrapedData.full_article_text || scrapedData.full_text || scrapedData.content || '').trim();
const rssTitle = (originalItem.title || '').trim();

// 6. CLEAN THE TEXT
const cleanedText = cleanArticleText(rawText);

// 7. Финальный объект
const finalArticle = {
  source_url: originalItem.link || originalItem.url || scrapedResult?.['resolved-url'] || '',
  rss_title: rssTitle,
  pubDate: originalItem.pubDate || originalItem.isoDate || '',
  author: originalItem.author || originalItem.creator || originalItem['dc:creator'] || '',
  scraped_title: scrapedTitle || rssTitle,
  full_text: cleanedText,
  processed_at: new Date().toISOString(),
  error: false,
  quality_flags: {
    title_from_scraping: scrapedTitle.length > 0,
    text_length: cleanedText.length,
    raw_text_length: rawText.length,
    cleanup_reduced_by: rawText.length - cleanedText.length,
    has_meaningful_content: cleanedText.length > 100
  }
};

return { json: finalArticle };

// Получаем все статьи с предыдущего шага
const allArticles = $input.all();

try {
  // Фильтруем только успешные статьи (без ошибок)
  const successfulArticles = allArticles
    .map(item => item.json)
    .filter(article => !article.error);

  const errorCount = allArticles.length - successfulArticles.length;

  // Возвращаем объект с массивом статей и метаданными
  return {
    json: {
      articles: successfulArticles,
      metadata: {
        total_processed: allArticles.length,
        successful: successfulArticles.length,
        errors: errorCount,
        processed_at: new Date().toISOString()
      }
    }
  };

} catch (error) {
  return {
    json: {
      articles: [],
      metadata: {
        total_processed: 0,
        successful: 0,
        errors: allArticles.length,
        error_message: error.message
      }
    }
  };
}
